namespace ProductReviewsDemo.Infrastructure
{
    public static class ReviewFormatter
    {
        public static string SanitizeAndFormat(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
            {
                return string.Empty;
            }

            var encoded = HttpUtility.HtmlEncode(input);

            encoded = encoded.Replace("\r\n", "\n").Replace("\r", "\n");
            encoded = System.Text.RegularExpressions.Regex.Replace(encoded, @"\*\*(.+?)\*\*", "<strong>$1</strong>");
            encoded = System.Text.RegularExpressions.Regex.Replace(encoded, @"\*(.+?)\*", "<em>$1</em>");
            encoded = encoded.Replace("\n", "<br />");

            return encoded;
        }
    }
}

namespace ProductReviewsDemo.Controllers
{
    using ProductReviewsDemo.Infrastructure;
    using ProductReviewsDemo.Models;

    public class ProductsController : Controller
    {
        private readonly ApplicationDbContext _db = new ApplicationDbContext();

        public async Task<ActionResult> Details(int id)
        {
            var product = await _db.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null)
            {
                return HttpNotFound();
            }

            var model = new ProductReviewsViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedUtc)
                    .Select(r => new ReviewDisplayViewModel
                    {
                        AuthorName = r.AuthorName,
                        CreatedUtc = r.CreatedUtc,
                        FormattedContent = ReviewFormatter.SanitizeAndFormat(r.Content)
                    })
                    .ToList()
            };

            return View(model);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }

            base.Dispose(disposing);
        }
    }
}

@model ProductReviewsDemo.Models.ProductReviewsViewModel

@{
    ViewBag.Title = Model.ProductName;
}

<h1>@Model.ProductName</h1>

<section class="product-reviews">
    <h2>Reviews</h2>

    @if (Model.Reviews == null || !Model.Reviews.Any())
    {
        <p>No reviews yet.</p>
    }
    else
    {
        foreach (var review in Model.Reviews)
        {
            <article class="review">
                <header>
                    <strong>@review.AuthorName</strong>
                    <span> - @review.CreatedUtc.ToLocalTime().ToString("MMM d, yyyy h:mm tt")</span>
                </header>
                <div class="review-content">
                    @Html.Raw(review.FormattedContent)
                </div>
            </article>
        }
    }
}